import React, { useEffect, useRef } from 'react'

declare global {
  interface Window {
    ckplayer: any
  }
}

// Ensure ckplayer.js is available in public folder or CDN
const ckUrl = `/ckplayer/ckplayer.js`

interface CkplayerProps {
  url?: string
  tableData?: any
  [key: string]: any
}

const Ckplayer: React.FC<CkplayerProps> = ({ url, tableData }) => {
  const ckplayerRef = useRef<any>(null)

  useEffect(()=> {
    // Logic for rtmpUrlTemplate replacement if needed
    // if(tableData?.table?.device?.settings?.rtmpUrlTemplate && tableData.table.device.settings.rtmpUrlTemplate.indexOf('$$')>-1) {
    // }

    let finalUrl = url
    if (tableData?.id && tableData?.table?.device?.settings?.rtmpUrlTemplate && tableData.table.device.settings.rtmpUrlTemplate.indexOf('$$') > -1) {
        finalUrl = tableData.table.device.settings.rtmpUrlTemplate.replace('$$', tableData?.id)
    }

    let videoObject = {
      container: tableData?.id ? `#${tableData?.id}` : '#video_ckplayer', 
      variable: tableData?.id ?  `player${tableData?.id}` : 'playervideo_ckplayer', 
      autoplay: true,
      video: finalUrl,
      live: true, 
      debug: true,
      flashplayer: false,
      mobileCkControls: false
    }

    let ckplayer;
    if(window.ckplayer) {
      ckplayer = new window.ckplayer(videoObject)
      ckplayerRef.current = ckplayer
    } else {
      const elem = document.createElement('script')
      elem.src = ckUrl
      elem.type = 'text/javascript'
      elem.onload = function () {
        if(window.ckplayer) {
          ckplayer = new window.ckplayer(videoObject)
          ckplayerRef.current = ckplayer
        }
      }
      elem.onerror = function (event) {
        console.error("Ckplayer script load error", event)
      }
      document.head.appendChild(elem)
    }

  }, [ url, tableData ])

  return (
    <>
      <div id={tableData?.id || "video_ckplayer" } className="video_ck w-100 h-100" style={{ width: '100%', height: '100%' }}></div>
    </>
  )
}

export default Ckplayer

import React, { useRef, useState, useEffect } from 'react'
import EZUIKit from 'ezuikit-js'
import { createAPI } from '@airiot/client'

interface EzuikitVideoProps {
  tableData?: any
  videoAction?: string
  cellKey?: string
  videoData?: any
  url?: string
  accessToken?: string
  [key: string]: any
}

const EzuikitVideo: React.FC<EzuikitVideoProps> = (props) => {
  const { tableData, videoAction="preview", cellKey, videoData } = props
  const ezuikitContainer = useRef<HTMLDivElement>(null)
  const ezuikitVideoContainer = useRef<HTMLDivElement>(null)
  const [ ezopen, setEzopen ] = useState<{url?: string, accessToken?: string}>({ url: props?.url, accessToken: props?.accessToken })
  const player = useRef<any>(null)
  const tableDataId = tableData?.id || 'name'
  const randows = Math.random()

  const check = () => {
    if(typeof window !== "undefined") {
      let userAgentInfo = window.navigator.userAgent
      let agents = new Array("Android", "iPhone", "SymbianOS", "Windows Phone", "iPad", "iPod")
      let flag = true;
      for(let i=0;i<agents.length;i++) {
        if(userAgentInfo.indexOf(agents[i])>0) {
          flag = false;
          break;
        }
      }
      return flag
    }
    return true
  }

  useEffect(()=>{
    if(ezopen?.url && ezopen?.accessToken && tableDataId) {
      let containerElement = document.getElementById(`video-ezuikit-${cellKey}`)
      let clientHeight = containerElement?.clientHeight || 400
      let clientWidth = containerElement?.clientWidth || '100%'

      let videoContainer = document.getElementById(`video-container-${tableDataId}-${cellKey}-${randows || 0}`)
      if (videoContainer) videoContainer.innerHTML = ''

      const isMobile = check()

      // if(player.current) { player.current.stop(); player.current = null }

      try {
          player.current = new EZUIKit.EZUIKitPlayer({
            id: `video-container-${tableDataId}-${cellKey}-${randows || 0}`, // 视频容器ID
            accessToken: ezopen.accessToken,
            url: ezopen.url,
            width: clientWidth,
            height: clientHeight,
            template: !isMobile ? 'mobileLive' : 'theme',
            autoplay: true
          })
      } catch (e) {
          console.error("EZUIKit init failed", e)
      }
    }
  }, [ ezopen?.url, ezopen?.accessToken, tableDataId, cellKey ])

  const getTableSchema = async (tableId: string) => {
    const api = createAPI({ resource: 'core/t/schema' })
    try {
      const { json } = await api.get(tableId) as any
      return json
    } catch (err) {
      console.error("Get table schema failed", err)
      return {}
    }
  }

  const getUrl = async (id: string, tableId: string, driverInstanceId: string, type: string) => {
    const table = await getTableSchema(tableId)
    const groupId = table?.device?.groupId
    if (groupId) {
      const api = createAPI({ resource: 'driver/driver/httpProxy' })
      api.fetch(`?type=${type}&groupId=${groupId}`, {
        method: 'POST',
        body: JSON.stringify({
          table: tableId, id, driverInstanceId
        })
      })
        .then(({ json }: any) => {
          setEzopen(json?.data?.data)
        })
        .catch(err => console.error(err))
    }
  }

  useEffect(() => {
    const tableId = tableData?.table?.id || tableData?.table
    const driverInstanceId = videoData?.driverInstanceId
    if(videoAction == 'preview' && driverInstanceId && tableId && tableData?.id) getUrl(tableData?.id, tableId, driverInstanceId, 'ezopenPreview')
    if(videoAction == 'record' && driverInstanceId && tableId && tableData?.id) getUrl(tableData?.id, tableId, driverInstanceId, 'ezopenRecord')
  }, [ tableData?.id, videoAction, videoData?.driverInstanceId ])

  useEffect(() => {
    return () => { if(player.current && typeof player.current.stop === 'function') { player.current.stop() } }
  }, [])

  return (
    <>
      <div className='video-ezuikit' id={`video-ezuikit-${cellKey}`} ref={ezuikitVideoContainer} style={{ width: '100%', height: '100%' }}>
        <div id={`video-container-${tableDataId}-${cellKey}-${randows || 0}`} ref={ezuikitContainer}></div>
      </div>
    </>
  )
}

export { EzuikitVideo }
export default EzuikitVideo

import React, { useRef, useState, useEffect } from 'react'
import isEmpty from 'lodash/isEmpty'
import isFunction from 'lodash/isFunction'
import isBoolean from 'lodash/isBoolean'
import { getConfig, createAPI } from '@airiot/client'
const config = getConfig()

declare global {
  interface Window {
    JessibucaPro: any
    jessibuca: any
  }
}

// Helper for protocol
const getProtocol = () => window.location.protocol.replace(':', '')
const appendQuery = (url: string, key: string, value?: string) => {
  if (!value) return url
  const separator = url.includes('?') ? '&' : '?'
  return `${url}${separator}${key}=${value}`
}

interface JessibucaVideoProps {
  jessConfigute?: any
  url?: string
  tableData?: any
  type?: string
  style?: React.CSSProperties
  backUrl?: string
  value?: any
  changeTime?: any
  videoData?: any
  resetStreamType?: (type: string) => void
  videoAction?: string
  reload?: any
  videoType?: any
  setReload?: (val: any) => void
  timerRef?: any
  errorReload?: number
  fullscreenStreamType?: boolean
  callback?: any
  playback?: any
  driverInstanceId?: string
  cellKey?: string
  streamType?: string
}

const JessibucaVideo: React.FC<JessibucaVideoProps> = (props) => {
  const { 
    jessConfigute = {}, 
    url, 
    tableData, 
    style, 
    backUrl, 
    videoData, 
    videoAction = "preview", 
    reload, 
    setReload, 
    timerRef, 
    errorReload = 5, 
    fullscreenStreamType, 
    playback 
  } = props

  const container = useRef<HTMLDivElement>(null)
  const jessibucaPlayer = useRef<any>(null)

  const jessUrl = videoData?.url || url
  const [videoUrl, setVideoUrl] = useState(jessUrl)

  const driverInstanceId = videoData?.driverInstanceId || props?.driverInstanceId

  const previousVideoUrl = useRef<string | null>(null)
  const isCreatingPlayer = useRef(false)
  const isCancelled = useRef(false)
  const pendingVideoUrl = useRef<string | null>(null)
  const hasPlayedBefore = useRef(false)
  const stopStreamCallCount = useRef<any>({})
  const lastPlayState = useRef<any>(null)

  const host = window.location.host

  const reloadTime = (msg: string) => {
    console.log(msg)
    if (timerRef?.current) clearInterval(timerRef.current)
    if (setReload && timerRef) {
      timerRef.current = setInterval(() => {
        setReload((prev: number) => prev + 1)
      }, errorReload * 1000)
    }
  }

  const errorFunc = (jessibuca: any) => {
    jessibuca.on("error", function () {
      reloadTime('视频播放异常error')
    })
    jessibuca.on("timeout", function () {
